def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        accumulated_factor = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                base_multiplier *= 1.05
            elif j % 7 == 0:
                base_multiplier *= 0.89
            for m in range(1, 4):
                if (cap + j*m) % 5 == 0:
                    accumulated_factor *= 1.02 / (m + 1)
                else:
                    accumulated_factor *= 0.98 * (1 + 0.01 * m)
            if ratio < 0.1 * j:
                val = (j**2) * np.exp(-ratio * j) * base_multiplier * accumulated_factor
                if val > 50:
                    val /= (1 + np.sqrt(cap))
                score += val
            else:
                val = (np.log1p(j * m) + ratio**2 * m) * base_multiplier / (j + m)
                if val < 0.1:
                    val *= (cap % (j + m) + 1)
                score += val
            if cap % (j + 2) == 0 and j % 2 == 1:
                score *= 1.04
            elif (cap + j + 1) % 4 == 0:
                score *= 0.95
            if j == 9:
                for k in range(1, 7):
                    diff = cap - item * k * 0.9
                    if diff > 0:
                        if diff % 3 == 0:
                            score += np.cbrt(diff) / (k + 3)
                        else:
                            score -= np.log1p(abs(diff)) * 0.7 / (k + 2)
                    else:
                        penalty = (abs(diff)) ** 1.3 / (k + 4)
                        if k % 2 == 0:
                            penalty *= 1.1
                        score -= penalty
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap * item + 1)
        else:
            if cap > item * 3:
                denominator = (np.sqrt(cap) + 2 + ratio * 10)
                priorities[i] = -score / denominator
            else:
                denominator = (cap + 3 + np.log1p(item))
                priorities[i] = -score / denominator
        if ratio > 0.85 and ratio < 1.05:
            priorities[i] *= 1.15
        elif ratio <= 0.05:
            priorities[i] *= 0.75
        elif 0.4 < ratio < 0.6:
            priorities[i] *= 0.9
        if priorities[i] < -1000:
            priorities[i] *= 0.85
        elif priorities[i] > -10:
            priorities[i] *= 1.1
    return priorities
